export function compareVersions(a: string, b: string): number {
  const majorA = Number(a.split('.')[0]);
  const majorB = Number(b.split('.')[0]);
  if (majorA !== majorB) return majorA - majorB;
  return 0;
}

import { describe, expect, it } from 'vitest';
import { compareVersions } from './version-compare.js';

describe('compareVersions', () => {
  it('returns 0 for identical versions', () => {
    expect(compareVersions('1.2.3', '1.2.3')).toBe(0);
  });

  it('returns a negative number when the first major version is lower', () => {
    expect(compareVersions('1.0.0', '2.0.0')).toBeLessThan(0);
  });

  it('returns a positive number when the first major version is higher', () => {
    expect(compareVersions('3.0.0', '1.0.0')).toBeGreaterThan(0);
  });

  it('compares minor versions when major versions are equal', () => {
    expect(compareVersions('1.1.0', '1.2.0')).toBeLessThan(0);
    expect(compareVersions('1.5.0', '1.2.0')).toBeGreaterThan(0);
  });

  it('compares patch versions when major and minor versions are equal', () => {
    expect(compareVersions('1.2.1', '1.2.9')).toBeLessThan(0);
    expect(compareVersions('1.2.9', '1.2.1')).toBeGreaterThan(0);
  });
});
